where.if:
and exists (
    select 1
    from inventory_sku_warehouse_stock st
    where st.spu_id = inventory_overview_spu_read_model.spu_id
      and concat_ws('|', st.warehouse_kind, st.warehouse_ref_type, coalesce(st.warehouse_id, ''), coalesce(st.warehouse_name, '')) = #{warehouseKey}
)

and exists (
    select 1
    from inventory_sku_warehouse_stock st
    where st.sku_id = inventory_overview_sku_read_model.sku_id
      and concat_ws('|', st.warehouse_kind, st.warehouse_ref_type, coalesce(st.warehouse_id, ''), coalesce(st.warehouse_name, '')) = #{warehouseKey}
)

mapper.select:
select *
from inventory_stock_ledger

    and stock_id = #{stockId}
    and sku_id = #{skuId}
    and spu_id = #{spuId}
    and operation_type = #{operationType}
    and biz_no = #{bizNo}

order by operate_time desc, ledger_id desc

mapper.sql:
select concat('INV:', sha2(concat_ws('|', 'SKU', sk.sku_id, 'OFFICIAL_MASTER', src.master_warehouse_name), 256)) as stock_key
from (

) sk
join (

) b on b.sku_id = sk.sku_id
join (

) src on src.repository_scope = b.source_scope
     and src.master_sku = b.master_sku
     and coalesce(src.master_product_name, '') = coalesce(b.master_product_name, '')
where sk.spu_id = #{spuId}
union all
select concat('INV:', sha2(concat_ws('|', 'SKU', sk.sku_id, 'SOURCE_UNBOUND'), 256)) as stock_key
from (

) sk
where sk.spu_id = #{spuId}
  and exists (
      select 1
      from (

      ) pw
      where pw.spu_id = sk.spu_id
        and pw.warehouse_kind = 'official'
  )
  and not exists (
      select 1
      from (

      ) b
      where b.sku_id = sk.sku_id
  )
union all
select concat('INV:', sha2(concat_ws('|', 'SKU', sk.sku_id, 'UNMATCHED_OFFICIAL'), 256)) as stock_key
from (

) sk
where sk.spu_id = #{spuId}
  and exists (
      select 1
      from (

      ) b
      where b.sku_id = sk.sku_id
  )
  and not exists (
      select 1
      from (

      ) b
      join (

      ) src
        on src.repository_scope = b.source_scope
       and src.master_sku = b.master_sku
       and coalesce(src.master_product_name, '') = coalesce(b.master_product_name, '')
      where b.sku_id = sk.sku_id
  )
union all
select concat('INV:', sha2(concat_ws('|', 'SKU', sk.sku_id, 'THIRD_PARTY_WAREHOUSE', pw.warehouse_id), 256)) as stock_key
from (

) sk
join (

) pw on pw.spu_id = sk.spu_id
 and pw.warehouse_kind = 'third_party'
where sk.spu_id = #{spuId}
union all
select concat('INV:', sha2(concat_ws('|', 'SKU', sk.sku_id, 'NO_WAREHOUSE'), 256)) as stock_key
from (

) sk
where sk.spu_id = #{spuId}
  and not exists (
      select 1
      from (

      ) pw
      where pw.spu_id = sk.spu_id
  )
  and not exists (
      select 1
      from (

      ) b
      where b.sku_id = sk.sku_id
  )

mapper.delete:
delete from inventory_sku_warehouse_stock
where spu_id = #{spuId}
  and stock_key not in (
      select stock_key
      from (

      ) current_stock_keys
  )

mapper.insert:
insert into inventory_sku_warehouse_stock( stock_key, spu_id, sku_id, seller_id, system_sku_code, warehouse_kind, warehouse_ref_type, warehouse_id, warehouse_code, warehouse_name, source_scope, source_master_warehouse_name, source_inventory_scope, source_inventory_attribute, source_total_qty, source_available_qty, source_in_transit_qty, source_snapshot_time, platform_total_qty, platform_reserved_qty, platform_in_transit_qty, pending_available_inbound_qty, pending_source_deduction_qty, platform_available_qty, effective_status, calc_time, create_by, create_time, update_by, update_time, remark ) select concat('INV:', sha2(concat_ws('|', 'SKU', sk.sku_id, 'OFFICIAL_MASTER', src.master_warehouse_name), 256)), sk.spu_id, sk.sku_id, sk.seller_id, sk.system_sku_code, 'official', 'OFFICIAL_MASTER', null, '', src.master_warehouse_name, 'OFFICIAL_MASTER', src.master_warehouse_name, 'COMPREHENSIVE', '0', src.source_total_qty, src.source_available_qty, src.source_in_transit_qty, src.source_snapshot_time, 0, 0, 0, 0, 0, 0, case when src.source_available_qty > 0 then 'OUT_OF_STOCK' when src.source_in_transit_qty > 0 then 'SOURCE_ONLY_IN_TRANSIT' else 'NO_SOURCE' end, sysdate(), #{operator}, sysdate(), #{operator}, sysdate(), '来源库存刷新生成' from (
) sk join (
) b on b.sku_id = sk.sku_id join (
) src on src.repository_scope = b.source_scope and src.master_sku = b.master_sku and coalesce(src.master_product_name, '') = coalesce(b.master_product_name, '') where sk.spu_id = #{spuId} on duplicate key update spu_id = values(spu_id), seller_id = values(seller_id), system_sku_code = values(system_sku_code), source_total_qty = values(source_total_qty), source_available_qty = values(source_available_qty), source_in_transit_qty = values(source_in_transit_qty), source_snapshot_time = values(source_snapshot_time), warehouse_kind = 'official', warehouse_ref_type = 'OFFICIAL_MASTER', warehouse_name = values(warehouse_name), source_scope = 'OFFICIAL_MASTER', source_master_warehouse_name = values(source_master_warehouse_name), platform_available_qty = greatest(0, least(platform_total_qty, greatest(0, values(source_available_qty) - pending_source_deduction_qty)) - platform_reserved_qty), effective_status = case when greatest(0, least(platform_total_qty, greatest(0, values(source_available_qty) - pending_source_deduction_qty)) - platform_reserved_qty) > 0 then 'IN_STOCK' when values(source_available_qty) <= 0 and values(source_in_transit_qty) > 0 then 'SOURCE_ONLY_IN_TRANSIT' when values(source_available_qty) <= 0 and values(source_in_transit_qty) <= 0 then 'NO_SOURCE' else 'OUT_OF_STOCK' end, calc_time = sysdate(), update_by = #{operator}, update_time = sysdate()

