) sk where sk.spu_id = #{spuId} and exists ( select 1 from (
) pw where pw.spu_id = sk.spu_id and pw.warehouse_kind = 'official' ) and not exists ( select 1 from (
) b where b.sku_id = sk.sku_id ) on duplicate key update spu_id = values(spu_id), seller_id = values(seller_id), system_sku_code = values(system_sku_code), warehouse_kind = 'official', warehouse_ref_type = 'SOURCE_UNBOUND', platform_available_qty = 0, effective_status = 'SOURCE_UNBOUND', calc_time = sysdate(), update_by = #{operator}, update_time = sysdate()

insert into inventory_sku_warehouse_stock( stock_key, spu_id, sku_id, seller_id, system_sku_code, warehouse_kind, warehouse_ref_type, warehouse_id, warehouse_code, warehouse_name, source_scope, source_master_warehouse_name, source_inventory_scope, source_inventory_attribute, source_total_qty, source_available_qty, source_in_transit_qty, source_snapshot_time, platform_total_qty, platform_reserved_qty, platform_in_transit_qty, pending_available_inbound_qty, pending_source_deduction_qty, platform_available_qty, effective_status, calc_time, create_by, create_time, update_by, update_time, remark ) select concat('INV:', sha2(concat_ws('|', 'SKU', sk.sku_id, 'UNMATCHED_OFFICIAL'), 256)), sk.spu_id, sk.sku_id, sk.seller_id, sk.system_sku_code, 'official', 'UNMATCHED_OFFICIAL', null, '', '官方仓（未匹配来源库存）', 'OFFICIAL_MASTER', '', 'COMPREHENSIVE', '0', 0, 0, 0, null, 0, 0, 0, 0, 0, 0, 'NO_SOURCE', sysdate(), #{operator}, sysdate(), #{operator}, sysdate(), '官方仓无来源库存占位行' from (
