) src on src.repository_scope = b.source_scope and src.master_sku = b.master_sku and coalesce(src.master_product_name, '') = coalesce(b.master_product_name, '') where b.sku_id = sk.sku_id ) on duplicate key update spu_id = values(spu_id), seller_id = values(seller_id), system_sku_code = values(system_sku_code), warehouse_kind = 'official', warehouse_ref_type = 'UNMATCHED_OFFICIAL', platform_available_qty = 0, effective_status = 'NO_SOURCE', calc_time = sysdate(), update_by = #{operator}, update_time = sysdate()

